import { Liveblocks } from "@liveblocks/node";
import { NextResponse } from "next/server";

const liveblocks = new Liveblocks({
  secret: process.env.LIVEBLOCKS_SECRET_KEY!,
});

export async function POST(request: Request) {
  let body: unknown;
  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  if (
    typeof body !== "object" ||
    body === null ||
    Array.isArray(body)
  ) {
    return NextResponse.json({ error: "Request body must be a JSON object" }, { status: 400 });
  }

  const { room, userId, role } = body as Record<string, unknown>;

  if (!room || typeof room !== "string") {
    return NextResponse.json({ error: "Missing or invalid field: room" }, { status: 400 });
  }

  if (!userId || typeof userId !== "string") {
    return NextResponse.json({ error: "Missing or invalid field: userId" }, { status: 400 });
  }

  if (!role || typeof role !== "string") {
    return NextResponse.json({ error: "Missing or invalid field: role" }, { status: 400 });
  }

  if (role !== "editor" && role !== "viewer") {
    return NextResponse.json(
      { error: 'Invalid role: must be "editor" or "viewer"' },
      { status: 400 }
    );
  }

  const session = liveblocks.prepareSession(userId, {
    userInfo: { role },
  });

  if (role === "viewer") {
    session.allow(room, session.READ_ACCESS);
  } else {
    session.allow(room, session.FULL_ACCESS);
  }

  const { status, body: responseBody } = await session.authorize();

  return new Response(responseBody, {
    status,
    headers: { "Content-Type": "application/json" },
  });
}

"use client";

import { useSearchParams } from "next/navigation";
import { LiveblocksProvider, RoomProvider, useStorage, useMutation, useStatus } from "@liveblocks/react";
import { LiveObject } from "@liveblocks/client";

type RoomPageParams = {
  params: { roomId: string };
};

export default function RoomPage({ params }: RoomPageParams) {
  const searchParams = useSearchParams();
  const userId = searchParams.get("userId") ?? "anonymous";
  const role = (searchParams.get("role") ?? "viewer") as "editor" | "viewer";
  const roomId = params.roomId;

  return (
    <LiveblocksProvider
      authEndpoint={async (room) => {
        const res = await fetch("/api/liveblocks-auth", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ room, userId, role }),
        });
        return res.json();
      }}
    >
      <RoomProvider
        id={roomId}
        initialStorage={{ counter: 0 }}
      >
        <RoomContent role={role} />
      </RoomProvider>
    </LiveblocksProvider>
  );
}

function RoomContent({ role }: { role: "editor" | "viewer" }) {
  const counter = useStorage((root) => root.counter);
  const status = useStatus();

  const increment = useMutation(({ storage }) => {
    const current = storage.get("counter") as number;
    storage.set("counter", current + 1);
  }, []);

  return (
    <main>
      <span data-testid="connection-status">{status}</span>
      <span data-testid="counter-value">{counter}</span>
      <span data-testid="role-label">{role}</span>
      <button
        data-testid="increment-button"
        onClick={increment}
        disabled={role === "viewer"}
      >
        Increment
      </button>
    </main>
  );
}

